/**
 * Fetch trims from the API
 * Note: During build time (generateStaticParams), we skip trim fetching
 * Trims are fetched at runtime when the page is actually requested
 */
async function fetchTrims(
  year: string, 
  make: string, 
  model: string
): Promise<{ results: Array<{ label: string; modificationId: string }> } | null> {
  // Skip during build - will be populated at runtime
  if (process.env.NEXT_PHASE === 'phase-production-build') {
    return null
  }

  try {
    // Determine base URL for SSR
    let baseUrl = ''
    if (typeof window === 'undefined') {
      // Server-side: need absolute URL
      if (process.env.NEXT_PUBLIC_BASE_URL) {
        baseUrl = process.env.NEXT_PUBLIC_BASE_URL
      } else if (process.env.VERCEL_URL) {
        baseUrl = `https://${process.env.VERCEL_URL}`
      } else {
        baseUrl = 'http://localhost:3000'
      }
    }

    const params = new URLSearchParams({ year, make, model })
    const url = `${baseUrl}/api/vehicles/trims?${params.toString()}`

    const res = await fetch(url, {
      cache: 'no-store',  // Always fetch fresh for trim data
    })

    if (!res.ok) {
      console.error('[fetchTrims] API returned non-OK:', res.status, url)
      return null
    }
    return res.json()
  } catch (error) {
    console.error('[fetchTrims] Failed to fetch trims:', error)
    return null
  }
}

